  # Build phrases, but avoid repeating the verb for subsequent predicates.
          phrases = []
          for idx, triple in enumerate(triples):
              template = phrasing.get(triple.predicate)
              if template:
                  phrase = template.format(triple.object)
              else:
                  phrase = f"{triple.predicate} {triple.object}"
              # For the first predicate keep the verb, for the rest drop leading "has " or "was ".
              if idx > 0:
                  for prefix in ("has ", "was "):
                      if phrase.startswith(prefix):
                          phrase = phrase[len(prefix):]
                          break
              phrases.append(phrase)

          # Join the phrases into a fluent clause.
          if len(phrases) == 1:
              sentence_body = phrases[0]
          else:
              sentence_body = ", ".join(phrases[:-1]) + " and " + phrases[-1]

          sentence = f"{subject} {sentence_body}."
